const triggerData = $('Webhook').first(); 

// Esta línea se queda igual, pero ahora leerá del Webhook
const binaryData = triggerData.binary;

// 2. Comprobamos si hay PDF
if (binaryData && Object.keys(binaryData).length > 0) {
  // SI HAY: Lo inyectamos y ponemos una marca "hasPDF = true"
  items[0].binary = binaryData;
  items[0].json.hasPDF = true;
} else {
  // NO HAY: Solo ponemos la marca "hasPDF = false"
  items[0].json.hasPDF = false;
}

// 3. Devolvemos todo por la salida única de siempre
return items;

